<?php
 namespace WPAICG\Core\Providers\Azure\Methods; if (!defined('ABSPATH')) { exit; } function _shared_format_logic(string $instructions, array $history, array $ai_params): array { $messages = []; if (!empty($instructions)) { $messages[] = ['role' => 'system', 'content' => $instructions]; } foreach ($history as $msg) { $role = ($msg['role'] === 'bot') ? 'assistant' : $msg['role']; $content = isset($msg['content']) ? trim($msg['content']) : ''; if ($content !== '' && in_array($role, ['system', 'user', 'assistant'], true)) { if ($role === 'system' && !empty($instructions)) continue; $messages[] = ['role' => $role, 'content' => $content]; } } $body_data = ['messages' => $messages]; $param_map = [ 'temperature' => 'temperature', 'max_completion_tokens' => 'max_completion_tokens', 'top_p' => 'top_p', 'stop' => 'stop', ]; foreach ($param_map as $aipkit_key => $api_key) { if (isset($ai_params[$aipkit_key])) { $value = $ai_params[$aipkit_key]; if (in_array($api_key, ['temperature', 'top_p'])) { $body_data[$api_key] = floatval($value); } elseif ($api_key === 'max_tokens') { $body_data[$api_key] = absint($value); } elseif ($api_key === 'stop' && !empty($value)) { $body_data[$api_key] = is_string($value) ? [$value] : (is_array($value) ? $value : null); if (empty($body_data[$api_key])) unset($body_data[$api_key]); } } } unset($body_data['top_p']); unset($body_data['temperature']); return $body_data; }